form:Form.form:Scripts:
		var MyHASel=null;
var Edit=false;
var New=false;

function RefreshControls()
{
	//Desactivo los Controles de Cambio
	if (MyHASel==null)
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	} else 
	if (Edit)
	{
		CtrlEnabled("DATA"  , true );
		CtrlEnabled("ADD"   , false);
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , false);
		CtrlEnabled("ACCEPT", true );
		CtrlEnabled("CANCEL", true );
	} else
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , true );
		CtrlEnabled("DELETE", true );
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	}
}

function RefreshCustomDay(MyOBJ, mydate)
{    
	var t, d, preaux, MyROW, newval, fd, fh, he, hs, aux;

	//Obtengo la esperanza
	MyHopeDay=GetHope(Math.floor((str2date(mydate)-str2date("20000102"))/604800000)).FindElement2("DIA","f_dia",mydate);

	//Novedades
	for (d=0; d<Ctrl("arrHorasAut").CountRow(); d++)
	{
		MyROW=Ctrl("arrHorasAut").GetRow(d);

		if (MyHASel==null || MyROW.GetAttr("id")!=MyHASel.GetAttr("id"))                  
		{
			fd=MyROW.GetAttr("f_desde");
			fh=MyROW.GetAttr("f_hasta");				
			he=parseInt(MyROW.GetAttr("e_horainicio"),10);
			hs=parseInt(MyROW.GetAttr("e_horafin"),10);
	  } else
	  {
			fd=Ctrl("f_desde").GetXValue();
			fh=Ctrl("f_hasta").GetXValue();
			he=parseInt(Ctrl("e_horainicio").GetXValue(),10);
			hs=parseInt(Ctrl("e_horafin").GetXValue(),10);
	  }                                      

		if (fd>mydate) continue;
		if (fh<mydate) continue;

		if (MyHopeDay!=null)
		{           
			aux=new Array();      

			//marco toda roja			                        
			for (t=he; t<hs; t+=5) aux[(t-he)/5]=0;

			//marco segun validacion
			for (cur=MyHopeDay.FindElement("DETALLE").FirstChild(); cur!=null; cur=cur.Next())
			{            
				horfound=MyHOR[cur.FindElement("oi_tipohora").GetAttr("value")]; 

				hetest=parseInt(cur.GetAttr("e_horainicio"),10);
				hstest=parseInt(cur.GetAttr("e_horafin"),10);
				if (hetest>=hs) continue;
				if (hstest<=he) continue;         

				if (hetest<he) hetest=he;
				if (hstest>hs) hstest=hs;

				for (t=hetest; t<hstest; t+=5) 
					aux[(t-he)/5]=(horfound.auth=="1"?parseInt(horfound.id,10):-1);
			}
			aux[aux.length]=3;

			for (preaux=t=0; t<aux.length; t++)
			{
				if (aux[preaux]!=aux[t])
				{                 
					hetest=he+preaux*5;     
					hstest=he+t*5;

					switch(aux[preaux])
					{   
						case 0:
							newval=MyOBJ.SetValue(
								mydate,
								hetest,
								hstest,
								"Autorizacion de HORA",
								"AA0000",
								"AA0000",
								"No hay horas que autorizar de "+int2time(hetest)+" a "+int2time(hstest),
								"BAR"
							);     
							newval.MyID    =MyROW.GetAttr("id");
							newval.selected=MyHASel?((MyROW.GetAttr("id")==MyHASel.GetAttr("id"))?true:false):false;
						break;

						case -1:
							newval=MyOBJ.SetValue(
								mydate,
								hetest,
								hstest,
								"Autorizacion de HORA",
								"AAAA00",
								"AAAA00",
								"Las Horas no requieren autorizacion de "+int2time(hetest)+" a "+int2time(hstest),
								"BAR"
							);     
							newval.MyID    =MyROW.GetAttr("id");
							newval.selected=MyHASel?((MyROW.GetAttr("id")==MyHASel.GetAttr("id"))?true:false):false;
						break;  

						default:
							horfound=MyHOR[aux[preaux].toString()]; 

							newval=MyOBJ.SetValue(
								mydate,
								hetest,
								hstest,
								"Autorizacion de HORA",
								"00AA00",
								"00AA00",
								"Autorizada: "+horfound.label+" de "+int2time(hetest)+" a "+int2time(hstest),
								"BAR"
							);     
							newval.MyID    =MyROW.GetAttr("id");
							newval.selected=MyHASel?((MyROW.GetAttr("id")==MyHASel.GetAttr("id"))?true:false):false;
						break;
					}

					preaux=t;
				}
			}


		} else
		{
			newval=MyOBJ.SetValue(
				mydate,
				he,
				hs,
				"Autorizacion de HORA",
				"AA0000",
				"AA0000",
				"No hay horas que autorizar de "+int2time(he)+" a "+int2time(hs),
				"BAR"
			);    
			newval.MyID    =MyROW.GetAttr("id");
			newval.selected=MyHASel?((MyROW.GetAttr("id")==MyHASel.GetAttr("id"))?true:false):false;
		}

	}

	//Novedades
	for (t=0; t<Ctrl("arrNovedades").CountRow(); t++)
	{
		MyROW=Ctrl("arrNovedades").GetRow(t);

		ff=MyROW.GetAttr("f_fecha");		
		he=parseInt(MyROW.GetAttr("e_horainicio"),10);
		hs=parseInt(MyROW.GetAttr("e_horafin"),10);
	  horfound=MyHOR[MyROW.GetAttr("oi_tipohora")];
		if (ff!=mydate) continue;

		newval=MyOBJ.SetValue(
			ff,
			he,
			hs,
			"Novedad: "+horfound.label,
			horfound.color,
			horfound.color,
			"Novedad: "+horfound.label+" desde "+int2time(he)+" a "+int2time(hs),
			"STD"
		);    
	}
}         

function ReDrawAll(MyOBJ)
{
	var sd=Ctrl("ESPERANZA_PERIODO").TypedValue(); sd.setDate(sd.getDate()-sd.getDay()+0);
	var ed=Ctrl("ESPERANZA_PERIODO").TypedValue(); ed.setDate(ed.getDate()-ed.getDay()+6);
	var daylist=new Array();
	var mydate;

	for(mydate=str2date(date2str(sd)); mydate<=ed; mydate.setDate(mydate.getDate()+1))
		daylist.push(date2str(mydate));

	ReDraw(MyOBJ, daylist);
}

function ReDrawAllWait(refreshDisplay, refreshButton)
{
	NomadTimeout((refreshDisplay?"ReDrawAll(MyOBJ);":"")+(refreshButton?"RefreshControls();":""),100,"Actualizando la Vista...");
}

function OnClickHorario(obj, dte, value)
{      
	var MyROW, dme;
	if (value.MyID?false:true) return;   
	if (Edit) return;

	MyROW=Ctrl("arrHorasAut").GetRowByAttr("id", value.MyID);
	he=parseInt(MyROW.GetAttr("e_horainicio"),10);
	hs=parseInt(MyROW.GetAttr("e_horafin"),10);
	Ctrl("d_horas"      ).SetXValue("desde "+int2time(he)+" hasta "+int2time(hs));
	Ctrl("f_desde"      ).SetXValue(MyROW.GetAttr("f_desde"      ));
	Ctrl("f_hasta"      ).SetXValue(MyROW.GetAttr("f_hasta"      ));
	Ctrl("e_horainicio" ).SetXValue(MyROW.GetAttr("e_horainicio" ));
	Ctrl("e_horafin"    ).SetXValue(MyROW.GetAttr("e_horafin"    ));
	Ctrl("d_tipohoraaut").SetXValue(MyROW.GetAttr("d_tipohoraaut"));
	Ctrl("o_tipohoraaut").SetXValue(MyROW.GetAttr("o_tipohoraAut"));

	MyHASel=MyROW;
	ReDrawAll(MyOBJ);
	RefreshControls();
	New=false;
}

function AddHoraAut()
{
	NomadTimeout("pAddHoraAut();",100,"Generando el Registro....");       
}

function pAddHoraAut()
{       
	var dme;                         
	var newDate=new Date();
	MyROW=Ctrl("arrHorasAut").AddRow();
	MyROW.SetAttr("id"           ,"#"+datetime2str(newDate));
	MyROW.SetAttr("f_desde"      ,"");
	MyROW.SetAttr("f_hasta"      ,"");
	MyROW.SetAttr("e_horainicio" ,"");
	MyROW.SetAttr("e_horafin"    ,"");
	MyROW.SetAttr("d_tipohoraaut","");
	MyROW.SetAttr("o_tipohoraAut","");

	Ctrl("d_horas"      ).SetXValue("");
	Ctrl("f_desde"      ).SetXValue(MyROW.GetAttr("f_desde"      ));
	Ctrl("f_hasta"      ).SetXValue(MyROW.GetAttr("f_hasta"      ));
	Ctrl("e_horainicio" ).SetXValue(MyROW.GetAttr("e_horainicio" ));
	Ctrl("e_horafin"    ).SetXValue(MyROW.GetAttr("e_horafin"    ));
	Ctrl("d_tipohoraaut").SetXValue(MyROW.GetAttr("d_tipohoraaut"));
	Ctrl("o_tipohoraaut").SetXValue(MyROW.GetAttr("o_tipohoraAut"));

	MyHASel=MyROW;
	ReDrawAll(MyOBJ);
	RefreshControls();
	StartEdit();
	New=true;
} 

function TruncHoraAut()
{   
	var cur,hs,hlen,t,prev,first,objdias=new Array();                     
	if (MyHASel==null) return false;

	hs  =str2date(MyHASel.GetAttr("f_desde"));
	hlen=Math.floor((str2date(MyHASel.GetAttr("f_hasta"))-hs)/86400000)+1;

	//marco los dias con autorizacion	             
	for (t=0; t<hlen; t++)
		objdias[t]=0; 

	//marco los anteriores a 180 dias 
	var dias;
	if(Ctrl('CantidadDiasModificar') != undefined)
		dias = Ctrl('CantidadDiasModificar').GetXValue(); 
	else
		dias = 180;


	hs1=0;        
	hs2=NowDate(); hs2.setDate(hs2.getDate()-dias);
	hs2=Math.floor((hs2-hs)/86400000)+1;
	if (hs2<0) hs2=0;
	if (hs2>hlen) hs2=hlen;

	//incremento los dias bloquedos
	for (t=hs1; t<hs2; t++)
		objdias[t]++;

	//marco los dias que no se pueden eliminar
	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{       
		hs1=Math.floor((str2date(cur.GetAttr("f_ini"))-hs)/86400000);
		hs2=Math.floor((str2date(cur.GetAttr("f_fin"))-hs)/86400000)+1;
		if (hs1>hlen) continue;
		if (hs2<   0) continue;

		if (hs1<   0) hs1=0;
		if (hs2>hlen) hs2=hlen;

		//incremento los dias bloquedos
		for (t=hs1; t<hs2; t++)
			objdias[t]++;
	}

	//genero las autorizaciones pertinentes
	prev=0; first=true;
	for (t=0; t<hlen; t++)
	if ((objdias[t]?1:0)!=(objdias[prev]?1:0))
	{
		if (objdias[prev]?1:0)
		{      
			if (first)	
			{
				MyROW=MyHASel;
				first=false;
			} else
			{
				MyROW=Ctrl("arrHorasAut").AddRow();
				MyROW.SetAttr("id"           ,"#"+datetime2str(newDate));
				MyROW.SetAttr("e_horainicio" ,MyHASel.GetAttr("e_horainicio" ));
				MyROW.SetAttr("e_horafin"    ,MyHASel.GetAttr("e_horafin"    ));
				MyROW.SetAttr("d_tipohoraaut",MyHASel.GetAttr("d_tipohoraaut"));
				MyROW.SetAttr("o_tipohoraAut",MyHASel.GetAttr("o_tipohoraAut"));
			}

			aux=str2date(date2str(hs)); aux.setDate(aux.getDate()+prev);
			MyROW.SetAttr("f_desde",date2str(aux));
			aux=str2date(date2str(hs)); aux.setDate(aux.getDate()+t-1);
			MyROW.SetAttr("f_hasta",date2str(aux));

		}
		prev=t;
	} 

	he=parseInt(MyHASel.GetAttr("e_horainicio"),10);
	hs=parseInt(MyHASel.GetAttr("e_horafin"),10);
	Ctrl("d_horas"      ).SetXValue("desde "+int2time(he)+" hasta "+int2time(hs));
	Ctrl("f_desde"      ).SetXValue(MyHASel.GetAttr("f_desde"      ));
	Ctrl("f_hasta"      ).SetXValue(MyHASel.GetAttr("f_hasta"      ));
	Ctrl("e_horainicio" ).SetXValue(MyHASel.GetAttr("e_horainicio" ));
	Ctrl("e_horafin"    ).SetXValue(MyHASel.GetAttr("e_horafin"    ));
	Ctrl("d_tipohoraaut").SetXValue(MyHASel.GetAttr("d_tipohoraaut"));
	Ctrl("o_tipohoraaut").SetXValue(MyHASel.GetAttr("o_tipohoraAut"));

	ReDrawAllWait(true, true);
	return true;
} 

function DelHoraAut()
{  
	var now, maxfecha;

	var dias;
	if(Ctrl('CantidadDiasModificar') != undefined)
		dias = Ctrl('CantidadDiasModificar').GetXValue(); 
	else
		dias = 180;

	//Verifico si el dia esta bloqueado
	if ((NowDate()-str2date(MyHASel.GetAttr("f_hasta")))/86400000>dias)
	{       
		alert("No se puede Eliminar.\r\nLa fecha final es anterior a "+dias+" dias.");
		return false;
	}

	if ((NowDate()-str2date(MyHASel.GetAttr("f_desde")))/86400000>dias)
	{       
		if (confirm("No se puede Eliminar completamente.\r\nExisten procesamientos cerrados en el rango de fechas.\r\nDesea eliminar en los rangos posibles?"))
			return TruncHoraAut();
		return false;
	}

	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{                                
		if (MyHASel.GetAttr("f_desde")>cur.GetAttr("f_fin")) continue;
		if (MyHASel.GetAttr("f_hasta")<cur.GetAttr("f_ini")) continue;

		if (confirm("No se puede Eliminar completamente.\r\nExisten procesamientos cerrados en el rango de fechas.\r\nnDesea eliminar en los rangos posibles?"))
			return TruncHoraAut();
		return false;
	}


	Ctrl("arrHorasAut").DelRowByAttr("id", MyHASel.GetAttr("id"));

	MyHASel=null;
	ReDrawAllWait(true, true);
}


function StartEdit()
{            
	var now, cur;

	//Verifico si el rango de dias esta bloqueado
	if (MyHASel.GetAttr("f_desde")!="")
	{    
		var dias;
		if(Ctrl('CantidadDiasModificar') != undefined)
			dias = Ctrl('CantidadDiasModificar').GetXValue(); 
		else
			dias = 180;

		now=NowDate();
		if ((NowDate()-str2date(MyHASel.GetAttr("f_desde")))/86400000>dias)
		{
			alert("No se puede modificar.\r\nLa fecha inicial es anterior a "+dias+" dias.");
			return false;
		}

		for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
		{                                
			if (MyHASel.GetAttr("f_desde")>cur.GetAttr("f_fin")) continue;
			if (MyHASel.GetAttr("f_hasta")<cur.GetAttr("f_ini")) continue;

			alert("No se puede modificar.\r\nExisten procesamientos cerrados en el rango de fechas.");
			return false;
		}
	}  

	Edit=true;

	MyOBJ.EditStart();           
	MyOBJ.SelectStyle("00AA00","BAR");

	RefreshControls();     
}          

function EditCancel()
{         
	if (New)
	{
		Ctrl("arrHorasAut").DelRowByAttr("id", MyHASel.GetAttr("id"));
		MyHASel=null;
	} else
	{
		he=parseInt(MyHASel.GetAttr("e_horainicio"),10);
		hs=parseInt(MyHASel.GetAttr("e_horafin"),10);
		Ctrl("d_horas"      ).SetXValue("desde "+int2time(he)+" hasta "+int2time(hs));
		Ctrl("f_desde"      ).SetXValue(MyHASel.GetAttr("f_desde"      ));
		Ctrl("f_hasta"      ).SetXValue(MyHASel.GetAttr("f_hasta"      ));
		Ctrl("e_horainicio" ).SetXValue(MyHASel.GetAttr("e_horainicio" ));
		Ctrl("e_horafin"    ).SetXValue(MyHASel.GetAttr("e_horafin"    ));
		Ctrl("d_tipohoraaut").SetXValue(MyHASel.GetAttr("d_tipohoraaut"));
		Ctrl("o_tipohoraaut").SetXValue(MyHASel.GetAttr("o_tipohoraAut"));
	}
	Edit=false;
	New=false;

	MyOBJ.EditEnd();          
	ReDrawAllWait(true, true);
}       


function ChangeTime(obj, dte, timestart, timeend)
{     
	if ((Ctrl("f_desde").GetXValue()=="") || (Ctrl("f_hasta").GetXValue()==""))
	{
		Ctrl("f_desde").SetXValue(dte);
		Ctrl("f_hasta").SetXValue(dte);
	}

	if ((Ctrl("f_desde").GetXValue()>dte) || (Ctrl("f_hasta").GetXValue()<dte))
	{
		alert("Esta fuera del rango especificado de dias");
		return;
	}

	Ctrl("e_horainicio" ).SetXValue(timestart);
	Ctrl("e_horafin"    ).SetXValue(timeend);
	Ctrl("d_horas"      ).SetXValue("desde "+int2time(timestart)+" hasta "+int2time(timeend));

	ReDrawAllWait(true, false);
}


function EditAccept()
{    
	var t, cur; 

	if (Ctrl("e_horainicio").GetXValue()==Ctrl("e_horafin").GetXValue())
	{
		alert("Rango de Horas no especificado.");
		return false;
	}

	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{                                
		if (Ctrl("f_desde").GetXValue()>cur.GetAttr("f_fin")) continue;
		if (Ctrl("f_hasta").GetXValue()<cur.GetAttr("f_ini")) continue;

		alert("No se puede modificar.\r\nExisten procesamientos cerrados en el rango de fechas.");
		return false;
	}

	for (t=0; t<Ctrl("arrHorasAut").CountRow(); t++)
	{
		MyROW=Ctrl("arrHorasAut").GetRow(t);
		if (MyROW.GetAttr("id")==MyHASel.GetAttr("id")) continue;

		if (Ctrl("f_desde").GetXValue()>MyROW.GetAttr("f_hasta")) continue;
		if (Ctrl("f_hasta").GetXValue()<MyROW.GetAttr("f_desde")) continue;

		if (parseInt(Ctrl("e_horainicio").GetXValue(),10)>=parseInt(MyROW.GetAttr("e_horafin"   ),10)) continue;
		if (parseInt(Ctrl("e_horafin"   ).GetXValue(),10)<=parseInt(MyROW.GetAttr("e_horainicio"),10)) continue;

		//falta verificacion de rango de horas
		alert("La Autorizacion modificada se superpone con otra Autorizacion.");
		return false;
	}

	NomadTimeout("internalEditAccept()",100,"Actualizando la Vista...");
}

function internalEditAccept()
{
	MyHASel.SetAttr("f_desde"      , Ctrl("f_desde"      ).GetXValue());
	MyHASel.SetAttr("f_hasta"      , Ctrl("f_hasta"      ).GetXValue());
	MyHASel.SetAttr("e_horainicio" , Ctrl("e_horainicio" ).GetXValue());
	MyHASel.SetAttr("e_horafin"    , Ctrl("e_horafin"    ).GetXValue());
	MyHASel.SetAttr("d_tipohoraaut", Ctrl("d_tipohoraaut").GetXValue());
	MyHASel.SetAttr("o_tipohoraAut", Ctrl("o_tipohoraaut").GetXValue());
	Edit=false;
	New=false;

	MyOBJ.EditEnd();  
	OnChangePeriodo();
	RefreshControls();     
}
